code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            long[] a = new long[N];
            for (int i = 0; i < N; i++) {
                a[i] = sc.nextLong();
            }
            long sum = 0;
            for (int i = 0; i < N; i++) {
                sum += a[i];
            }
            for (int i = 0; i < N; i++) {
                System.out.print(sum - (N - 1) * a[i] + " ");
            }
            System.out.println();
        }
    }
}

